import { join } from 'node:path';
import { Module } from '@nestjs/common';
import { WorkflowModule } from 'workflow/nest';
import { AppController } from './app.controller.js';

// Force-enable manifest serving on Vercel
if (process.env.VERCEL) {
  process.env.WORKFLOW_PUBLIC_MANIFEST = '1';
}

// Load generated bundle data. These are generated by workflow-nest build
// in prebuild and compiled by nest build. Standard imports that NFT traces.
let manifestJson: string | undefined;
try {
  // @ts-ignore — generated at build time
  const { manifestJson: data } = await import('./_manifest-data.js');
  manifestJson = data;
} catch {}

// Load base64-encoded bundles for Vercel (where .mjs files aren't in Lambda)
for (const name of ['steps', 'workflows', 'webhook']) {
  try {
    // @ts-ignore — generated at build time
    const mod = await import(`./_${name}-bundle.js`);
    (globalThis as any)[`__workflowBundle_${name}`] = mod.bundleBase64;
  } catch {}
}

@Module({
  imports: [
    WorkflowModule.forRoot({
      skipBuild: !!process.env.VERCEL,
      ...(process.env.VERCEL
        ? { outDir: join(process.cwd(), 'dist', 'workflow') }
        : {}),
      ...(manifestJson ? { manifestJson } : {}),
    }),
  ],
  controllers: [AppController],
})
export class AppModule {}
